import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { userService } from '../../services/userService';
import toast from 'react-hot-toast';
import './Profile.css';

const Profile = () => {
  const { user, logout } = useAuth();
  const [editing, setEditing] = useState(false);
  const [form, setForm] = useState({
    name: user?.name || '',
    phone_no: user?.phoneNo || user?.phone_no || '',
    address: user?.address || '',
  });
  const [loading, setLoading] = useState(false);

  const handleSave = async () => {
    setLoading(true);
    try {
      await userService.updateUser(user.userId || user.user_id, { ...user, ...form });
      toast.success('Profile updated!');
      setEditing(false);
    } catch { toast.error('Update failed'); }
    finally { setLoading(false); }
  };

  return (
    <div className="profile-page">
      <div className="profile-card">
        <div className="profile-avatar-section">
          <div className="profile-avatar">{user?.name?.charAt(0).toUpperCase()}</div>
          <div>
            <h2>{user?.name}</h2>
            <span className={`role-badge ${user?.role?.toLowerCase()}`}>{user?.role}</span>
          </div>
        </div>

        <div className="profile-info">
          {editing ? (
            <div className="profile-form">
              <div className="form-group">
                <label>Full Name</label>
                <input value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} />
              </div>
              <div className="form-group">
                <label>Phone</label>
                <input value={form.phone_no} onChange={e => setForm({ ...form, phone_no: e.target.value })} />
              </div>
              <div className="form-group">
                <label>Address</label>
                <textarea value={form.address} onChange={e => setForm({ ...form, address: e.target.value })} rows={3} />
              </div>
              <div className="profile-actions">
                <button className="btn-save" onClick={handleSave} disabled={loading}>
                  {loading ? 'Saving...' : 'Save Changes'}
                </button>
                <button className="btn-cancel" onClick={() => setEditing(false)}>Cancel</button>
              </div>
            </div>
          ) : (
            <>
              <div className="info-grid">
                <div className="info-item"><span>📧 Email</span><p>{user?.email}</p></div>
                <div className="info-item"><span>📱 Phone</span><p>{user?.phoneNo || user?.phone_no || 'Not set'}</p></div>
                <div className="info-item"><span>📍 Address</span><p>{user?.address || 'Not set'}</p></div>
                <div className="info-item"><span>🗓️ Member Since</span><p>{user?.createdAt ? new Date(user.createdAt).toLocaleDateString() : 'N/A'}</p></div>
              </div>
              <div className="profile-actions">
                <button className="btn-edit" onClick={() => setEditing(true)}>Edit Profile</button>
                <button className="btn-logout" onClick={logout}>Logout</button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default Profile;
